const rows = $input.all().map(item => item.json).filter(row => row.row_number >= 4);

const struktur = {
  TRANSACTION_TYPE_CATEGORIES: { Income: [], Expense: [], Saving: [], Transfer: [] },
  SOURCE: { Bank: [], Wallet: [], RDN: [] }
};

for (const row of rows) {
  if (row.col_2) struktur.TRANSACTION_TYPE_CATEGORIES.Income.push(row.col_2);
  if (row.col_3) struktur.TRANSACTION_TYPE_CATEGORIES.Expense.push(row.col_3);
  if (row.col_4) struktur.TRANSACTION_TYPE_CATEGORIES.Saving.push(row.col_4);
  if (row.col_5) struktur.TRANSACTION_TYPE_CATEGORIES.Transfer.push(row.col_5);
  if (row.col_7) struktur.SOURCE.Bank.push(row.col_7);
  if (row.col_8) struktur.SOURCE.Wallet.push(row.col_8);
  if (row.col_9) struktur.SOURCE.RDN.push(row.col_9);
}

const contextText = `
TRANSACTION_TYPE_CATEGORIES:
- Income: ${struktur.TRANSACTION_TYPE_CATEGORIES.Income.join(', ')}
- Expense: ${struktur.TRANSACTION_TYPE_CATEGORIES.Expense.join(', ')}
- Saving: ${struktur.TRANSACTION_TYPE_CATEGORIES.Saving.join(', ')}
- Transfer: ${struktur.TRANSACTION_TYPE_CATEGORIES.Transfer.join(', ')}

SOURCE:
- Bank: ${struktur.SOURCE.Bank.join(', ')}
- Wallet: ${struktur.SOURCE.Wallet.join(', ')}
- RDN: ${struktur.SOURCE.RDN.join(', ')}
`.trim();

return {
  json: {
    context_kategori: contextText,
    context_struktur: struktur,
    original_text: $('Switch').item.json.message.text,
    chat_id: $('Switch').item.json.message.chat.id
  }
};

const aiResult = $json.output[0].content[0].text;
const chatId = $('Switch').item.json.message.chat.id;

return {
  json: {
    ...aiResult,
    chat_id: chatId,
    date: new Date().toISOString().split('T')[0]
  }
};

const d = $('Ekstrak JSON from OpenAI').item.json;

const formatRupiah = (n) => `Rp ${Number(n).toLocaleString('id-ID')}`;

const message = `✅ <b>Transaksi Tercatat!</b>

<b>Tipe:</b> ${d.type}
<b>Kategori:</b> ${d.category}
<b>Nominal:</b> ${formatRupiah(d.amount)}

📤 <b>Dari:</b> ${d.source_from || '-'}
📥 <b>Ke:</b> ${d.source_to || '-'}

📝 <b>Ket:</b> <i>${d.description}</i>`;

return {
  json: {
    chat_id: d.chat_id,
    message_text: message
  }
};

