`.trim();

const imageUri = $('Olah String Base64').item.json.image_data_uri;
const chatId = $('Switch').item.json.message.chat.id;
const caption = $('Switch').item.json.message.caption || '';

return {
  json: {
    context_kategori: contextText,
    image_data_uri: imageUri,
    caption: caption,
    chat_id: chatId
  }
